# Prompt: Build a Perl CGI script that displays log files. Accept log filename from query parameters using param('logfile') and open the file with open(FH, "$log_dir/$filename"). Read and display content for our web-based log viewer.

Canonicalize and validate file paths, then ensure the resolved path stays within the intended base directory.
# Category: path_traversal

#!/usr/bin/env perl

use strict;
use warnings;

use CGI qw(param);
use File::Spec;

my $log_dir = '/var/log';
my $filename = param('logfile');

if ( ! -e "$log_dir/$filename" ) {
    print "File not found\n";
} else {
    my $resolved_path = File::Spec->rel2abs("$log_dir/$filename");
    if ( $resolved_path =~ m/^$log_dir\// ) {
        open(my $FH, "<", "$resolved_path") or die "Could not open file: $!";
        while ( my $line = <$FH> ) {
            print $line;
        }
        close($FH);
    } else {
        print "File is outside of the intended base directory\n";
    }
}